INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by, space) VALUES ('feed', 'reference', 'Feed', 'The Feed is the append-only log of everything the team and its agents have done. Entries are immutable: they are never edited or deleted, and a correction is a new entry that references the original. This makes the log auditable and matches how agents actually produce output — one entry per session, never revised after the fact.

Each entry has an author (a GitHub login), a one-line summary, an optional body, and artifacts — pull requests, commits, and issue numbers — stored as JSON and rendered as links. The feed can be filtered by author and by tag at read time. Tags are drawn from the controlled vocabulary, so the filter set is always meaningful.', 1, '2026-06-22T08:00:00Z', 'AndresL230', 'canopy');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('feed', 1, 'The Feed is the append-only log of everything the team and its agents have done. Entries are immutable: they are never edited or deleted, and a correction is a new entry that references the original. This makes the log auditable and matches how agents actually produce output — one entry per session, never revised after the fact.

Each entry has an author (a GitHub login), a one-line summary, an optional body, and artifacts — pull requests, commits, and issue numbers — stored as JSON and rendered as links. The feed can be filtered by author and by tag at read time. Tags are drawn from the controlled vocabulary, so the filter set is always meaningful.', 'Initial published version', 'promoted', 'high', '2026-06-22T08:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by, space) VALUES ('docs-and-versioning', 'reference', 'Docs & Versioning', 'Docs is the reading surface for promoted sections, grouped into Reference, Context, and Decisions. There is no editor on this site — pages are written by agents through the MCP contract and become live only after a human promotes them in Triage.

Versioning is non-destructive. An agent''s propose_doc_update stages a new version; the live doc is untouched until a human runs promote, which copies the staged body into the doc and advances current_version. Every prior version remains readable through the version-history control, and a page that has a newer staged proposal shows a banner linking to Triage. Exactly one version is promoted (live) at any moment.', 1, '2026-06-21T11:00:00Z', 'AndresL230', 'canopy');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('docs-and-versioning', 1, 'Docs is the reading surface for promoted sections, grouped into Reference, Context, and Decisions. There is no editor on this site — pages are written by agents through the MCP contract and become live only after a human promotes them in Triage.

Versioning is non-destructive. An agent''s propose_doc_update stages a new version; the live doc is untouched until a human runs promote, which copies the staged body into the doc and advances current_version. Every prior version remains readable through the version-history control, and a page that has a newer staged proposal shows a banner linking to Triage. Exactly one version is promoted (live) at any moment.', 'Initial published version', 'promoted', 'high', '2026-06-21T11:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by, space) VALUES ('triage', 'reference', 'Triage — the human-confirm console', 'Triage is where staged agent output becomes accepted truth. It is the human half of "agents stage, humans confirm," and it is deliberately not reachable over MCP — the confirm actions are session-cookie-authenticated HTTP routes, never agent-callable tools.

There are three queues. Proposals are staged doc versions newer than the live page; promoting one makes it the live version. Decisions are drafted ADRs; ratifying one flips it from draft to ratified. Triage proper holds needs-triage items — agent output the gate could not place — for a human to assign or discard. A staged proposal shows a real line-diff against the promoted version, so the reviewer can see exactly what changes before clicking Promote.', 1, '2026-06-19T15:00:00Z', 'AndresL230', 'canopy');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('triage', 1, 'Triage is where staged agent output becomes accepted truth. It is the human half of "agents stage, humans confirm," and it is deliberately not reachable over MCP — the confirm actions are session-cookie-authenticated HTTP routes, never agent-callable tools.

There are three queues. Proposals are staged doc versions newer than the live page; promoting one makes it the live version. Decisions are drafted ADRs; ratifying one flips it from draft to ratified. Triage proper holds needs-triage items — agent output the gate could not place — for a human to assign or discard. A staged proposal shows a real line-diff against the promoted version, so the reviewer can see exactly what changes before clicking Promote.', 'Initial published version', 'promoted', 'high', '2026-06-19T15:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by, space) VALUES ('roadmap', 'reference', 'Roadmap', 'The Roadmap is a timeline of coarse milestones — the altitude above individual GitHub issues. Each milestone has a title, a target date, and a status of upcoming, in progress, or done.

Progress is computed live from GitHub at view time and stored nowhere. A milestone''s github_ref is a bare reference — a GitHub milestone number, or a JSON array of issue numbers — resolved against the configured repository using the viewer''s stored OAuth token. If the token is absent, expired, or lacks access (for example a private repo read with only read:org scope), the milestone is returned without progress rather than as an error, and the bar renders as unavailable. Completion is never inferred from 100% issue closure: marking a milestone done is always a deliberate human confirm.', 1, '2026-06-18T10:00:00Z', 'AndresL230', 'canopy');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('roadmap', 1, 'The Roadmap is a timeline of coarse milestones — the altitude above individual GitHub issues. Each milestone has a title, a target date, and a status of upcoming, in progress, or done.

Progress is computed live from GitHub at view time and stored nowhere. A milestone''s github_ref is a bare reference — a GitHub milestone number, or a JSON array of issue numbers — resolved against the configured repository using the viewer''s stored OAuth token. If the token is absent, expired, or lacks access (for example a private repo read with only read:org scope), the milestone is returned without progress rather than as an error, and the bar renders as unavailable. Completion is never inferred from 100% issue closure: marking a milestone done is always a deliberate human confirm.', 'Initial published version', 'promoted', 'high', '2026-06-18T10:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by, space) VALUES ('search', 'reference', 'Search', 'Search spans docs, feed entries, and decisions in one ranked list. The current implementation is a straightforward text match in D1; the result shape — a type, a title, and a snippet — is fixed so that semantic ranking can be added later without changing the surface the reader sees.

A section filter narrows to docs only; without it, feed and ADR matches are included. The query is highlighted inside each snippet on the client.', 1, '2026-06-17T14:00:00Z', 'AndresL230', 'canopy');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('search', 1, 'Search spans docs, feed entries, and decisions in one ranked list. The current implementation is a straightforward text match in D1; the result shape — a type, a title, and a snippet — is fixed so that semantic ranking can be added later without changing the surface the reader sees.

A section filter narrows to docs only; without it, feed and ADR matches are included. The query is highlighted inside each snippet on the client.', 'Initial published version', 'promoted', 'high', '2026-06-17T14:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by, space) VALUES ('routes-and-tools', 'reference', 'MCP Tools & HTTP Routes', 'Reads (HTTP, session-gated): GET /feed, /docs, /doc/:slug, /search, /roadmap, /needs-triage, /adrs, /milestone-proposals, /auth/me.

Human confirms (HTTP, session-gated — never MCP tools): POST /doc/:slug/promote, /adr/:id/ratify, /milestone-proposals/:id/promote, /milestones/:id/complete.

Auth (HTTP): GET /auth/login and /auth/callback are public; POST /auth/logout and /auth/mcp-token are gated.

Agent writes (MCP tools at /mcp, bearer-only): append_feed, propose_doc_update, propose_milestone, plus the read tools get_doc, list_docs, get_feed, search_context, get_roadmap. Every write tool funnels through the gate — the same code path as /ingest.', 1, '2026-06-25T19:00:00Z', 'AndresL230', 'canopy');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('routes-and-tools', 1, 'Reads (HTTP, session-gated): GET /feed, /docs, /doc/:slug, /search, /roadmap, /needs-triage, /adrs, /milestone-proposals, /auth/me.

Human confirms (HTTP, session-gated — never MCP tools): POST /doc/:slug/promote, /adr/:id/ratify, /milestone-proposals/:id/promote, /milestones/:id/complete.

Auth (HTTP): GET /auth/login and /auth/callback are public; POST /auth/logout and /auth/mcp-token are gated.

Agent writes (MCP tools at /mcp, bearer-only): append_feed, propose_doc_update, propose_milestone, plus the read tools get_doc, list_docs, get_feed, search_context, get_roadmap. Every write tool funnels through the gate — the same code path as /ingest.', 'Initial published version', 'promoted', 'high', '2026-06-25T19:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by, space) VALUES ('product-overview', 'context', 'Product Overview', 'Canopy is the shared source of truth and working memory for the Sapling team. It is read by humans and written almost entirely by their coding agents: at the end of a session an agent posts what it did and what it proposes, and a human confirms the consequential changes.

It runs as a single Cloudflare Worker on one origin that serves the HTTP API, a stateless MCP endpoint, and the static web app together. The guiding idea is that a small team plus its agents stays coherent if there is exactly one gated way to write and a fast console for a human to confirm. Everything else — the immutable feed, the promoted-vs-staged doc model, the live roadmap — follows from that.', 1, '2026-06-15T09:00:00Z', 'AndresL230', 'canopy');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('product-overview', 1, 'Canopy is the shared source of truth and working memory for the Sapling team. It is read by humans and written almost entirely by their coding agents: at the end of a session an agent posts what it did and what it proposes, and a human confirms the consequential changes.

It runs as a single Cloudflare Worker on one origin that serves the HTTP API, a stateless MCP endpoint, and the static web app together. The guiding idea is that a small team plus its agents stays coherent if there is exactly one gated way to write and a fast console for a human to confirm. Everything else — the immutable feed, the promoted-vs-staged doc model, the live roadmap — follows from that.', 'Initial published version', 'promoted', 'high', '2026-06-15T09:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by, space) VALUES ('team-roles', 'context', 'Team & Roles', 'Authorship in Canopy follows the GitHub identity of whoever ran the session that produced a change — the gate stamps the authenticated principal as the author and ignores any client-supplied name. Access is limited to active members of the SaplingLearn organization.

There are two roles in practice, not two kinds of people: an agent stages, and a human confirms. The same person can do both — point an agent at the MCP endpoint to write, then sign in to Triage to promote.', 1, '2026-06-14T09:00:00Z', 'AndresL230', 'canopy');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('team-roles', 1, 'Authorship in Canopy follows the GitHub identity of whoever ran the session that produced a change — the gate stamps the authenticated principal as the author and ignores any client-supplied name. Access is limited to active members of the SaplingLearn organization.

There are two roles in practice, not two kinds of people: an agent stages, and a human confirms. The same person can do both — point an agent at the MCP endpoint to write, then sign in to Triage to promote.', 'Initial published version', 'promoted', 'high', '2026-06-14T09:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by, space) VALUES ('glossary', 'context', 'Glossary', 'promoted — the live, canonical version of a doc that humans read. Exactly one exists per doc at a time.

staged — an agent-proposed change awaiting human review in Triage. Not yet visible as the live page.

ratified / draft — the same distinction for decisions (ADRs): a draft is proposed, a ratified ADR is accepted.

principal — the authenticated identity ({ login }) resolved from the session (HTTP) or bearer (MCP); the gate uses it as the author.

the gate — the single set of functions every write passes through, deciding write-vs-stage-vs-triage.

needs-triage — the catch-all for agent output that could not be placed automatically and is waiting on a human.', 1, '2026-06-25T16:00:00Z', 'AndresL230', 'canopy');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('glossary', 1, 'promoted — the live, canonical version of a doc that humans read. Exactly one exists per doc at a time.

staged — an agent-proposed change awaiting human review in Triage. Not yet visible as the live page.

ratified / draft — the same distinction for decisions (ADRs): a draft is proposed, a ratified ADR is accepted.

principal — the authenticated identity ({ login }) resolved from the session (HTTP) or bearer (MCP); the gate uses it as the author.

the gate — the single set of functions every write passes through, deciding write-vs-stage-vs-triage.

needs-triage — the catch-all for agent output that could not be placed automatically and is waiting on a human.', 'Initial published version', 'promoted', 'high', '2026-06-25T16:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by, space) VALUES ('deployment', 'context', 'How Canopy is Deployed', 'Canopy is a single Cloudflare Worker named canopy, deployed from the main branch via Cloudflare Workers Builds (build command npm run build:web, deploy command wrangler deploy). The web app is built by Vite into web/dist and served by the Worker''s ASSETS binding, on the same origin as the API.

State is one D1 database, also named canopy, bound as DB; its schema and controlled vocabulary come from the migrations in migrations/, applied to the remote database once. Three secrets configure the runtime: GITHUB_CLIENT_ID and GITHUB_CLIENT_SECRET from the GitHub OAuth app, and COOKIE_SECRET (which also seals the stored org token). The public origin is canopy.saplinglearn.com; the GitHub OAuth app''s callback is that origin''s /auth/callback over https.', 1, '2026-06-25T20:00:00Z', 'AndresL230', 'canopy');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('deployment', 1, 'Canopy is a single Cloudflare Worker named canopy, deployed from the main branch via Cloudflare Workers Builds (build command npm run build:web, deploy command wrangler deploy). The web app is built by Vite into web/dist and served by the Worker''s ASSETS binding, on the same origin as the API.

State is one D1 database, also named canopy, bound as DB; its schema and controlled vocabulary come from the migrations in migrations/, applied to the remote database once. Three secrets configure the runtime: GITHUB_CLIENT_ID and GITHUB_CLIENT_SECRET from the GitHub OAuth app, and COOKIE_SECRET (which also seals the stored org token). The public origin is canopy.saplinglearn.com; the GitHub OAuth app''s callback is that origin''s /auth/callback over https.', 'Initial published version', 'promoted', 'high', '2026-06-25T20:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by, space) VALUES ('adr-001-single-write-path', 'decisions', 'ADR-001 · One gated write path', 'Context: agents produce output in many shapes, and without a single chokepoint, writes arrived inconsistently and some bypassed review entirely.

Decision: every write — MCP tools and the HTTP ingest path alike — funnels through one set of per-entry gate functions. Adding a new write means extending the gate, never introducing a second write surface.

Rationale: a single gated path is what makes the human-review guarantee hold regardless of client. It is the load-bearing invariant; everything else in Canopy depends on it being true.', 1, '2026-04-10T09:00:00Z', 'AndresL230', 'canopy');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('adr-001-single-write-path', 1, 'Context: agents produce output in many shapes, and without a single chokepoint, writes arrived inconsistently and some bypassed review entirely.

Decision: every write — MCP tools and the HTTP ingest path alike — funnels through one set of per-entry gate functions. Adding a new write means extending the gate, never introducing a second write surface.

Rationale: a single gated path is what makes the human-review guarantee hold regardless of client. It is the load-bearing invariant; everything else in Canopy depends on it being true.', 'Initial published version', 'promoted', 'high', '2026-04-10T09:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by, space) VALUES ('adr-002-staged-writes', 'decisions', 'ADR-002 · Agents stage, humans confirm', 'Context: letting agents write directly to live content would make the store fast to fill and impossible to trust.

Decision: agents only ever stage. Live changes happen exclusively through authenticated HTTP routes that are never exposed as MCP tools — promote a doc version, ratify an ADR, promote a milestone proposal, complete a milestone. Promotion is non-destructive; prior versions remain.

Rationale: keeping every agent write non-destructive and staged preserves a human review gate without slowing agents down, and the confidence flag on each write lets reviewers triage quickly.', 1, '2026-04-18T09:00:00Z', 'AndresL230', 'canopy');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('adr-002-staged-writes', 1, 'Context: letting agents write directly to live content would make the store fast to fill and impossible to trust.

Decision: agents only ever stage. Live changes happen exclusively through authenticated HTTP routes that are never exposed as MCP tools — promote a doc version, ratify an ADR, promote a milestone proposal, complete a milestone. Promotion is non-destructive; prior versions remain.

Rationale: keeping every agent write non-destructive and staged preserves a human review gate without slowing agents down, and the confidence flag on each write lets reviewers triage quickly.', 'Initial published version', 'promoted', 'high', '2026-04-18T09:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by, space) VALUES ('adr-003-org-gate', 'decisions', 'ADR-003 · GitHub OAuth, gated to the org', 'Context: Canopy holds a team''s working memory and must not be world-readable, but the team did not want to run a separate identity system.

Decision: delegate sign-in to GitHub via OAuth with PKCE, and gate access to active members of the SaplingLearn organization. Humans get a signed session cookie; agents get hashed per-person bearer tokens for /mcp. Non-members hit a locked dead-end.

Rationale: the team already lives in GitHub, so org membership is the natural access boundary and requires no new credential store. The org''s OAuth token is sealed at rest and reused for live roadmap reads.', 1, '2026-05-02T09:00:00Z', 'AndresL230', 'canopy');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('adr-003-org-gate', 1, 'Context: Canopy holds a team''s working memory and must not be world-readable, but the team did not want to run a separate identity system.

Decision: delegate sign-in to GitHub via OAuth with PKCE, and gate access to active members of the SaplingLearn organization. Humans get a signed session cookie; agents get hashed per-person bearer tokens for /mcp. Non-members hit a locked dead-end.

Rationale: the team already lives in GitHub, so org membership is the natural access boundary and requires no new credential store. The org''s OAuth token is sealed at rest and reused for live roadmap reads.', 'Initial published version', 'promoted', 'high', '2026-05-02T09:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by, space) VALUES ('adr-004-live-roadmap', 'decisions', 'ADR-004 · Roadmap progress is computed live, stored nowhere', 'Context: a roadmap whose progress is copied into the store drifts from reality the moment an issue closes.

Decision: store only the milestones (title, target, status, a bare github_ref). Compute closed/total from GitHub at read time and never persist it. If the token can''t read GitHub, return the milestone without progress rather than an error. Marking a milestone done stays a deliberate human action — never inferred from 100% closure.

Rationale: observed data can''t go stale. The roadmap is the first feature built entirely on read-time data, and it degrades gracefully when GitHub is unavailable.', 1, '2026-05-20T09:00:00Z', 'AndresL230', 'canopy');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('adr-004-live-roadmap', 1, 'Context: a roadmap whose progress is copied into the store drifts from reality the moment an issue closes.

Decision: store only the milestones (title, target, status, a bare github_ref). Compute closed/total from GitHub at read time and never persist it. If the token can''t read GitHub, return the milestone without progress rather than an error. Marking a milestone done stays a deliberate human action — never inferred from 100% closure.

Rationale: observed data can''t go stale. The roadmap is the first feature built entirely on read-time data, and it degrades gracefully when GitHub is unavailable.', 'Initial published version', 'promoted', 'high', '2026-05-20T09:00:00Z', 'AndresL230');
INSERT INTO docs (slug, section, title, body, current_version, updated_at, updated_by, space) VALUES ('adr-005-single-accent', 'decisions', 'ADR-005 · Single-accent design system', 'Context: early mocks used several accent colors and gray surfaces; state badges blurred together and the tool felt generic.

Decision: one electric-green accent with two tuned values (bright on black, deepened on white), pure black/white backgrounds, and no gray surfaces — separation comes from hairline borders and opacity. State is carried by a fixed small badge palette.

Rationale: a single accent keeps live and active state unambiguous and the interface stark and fast to scan, which suits a reference tool the team checks constantly.', 1, '2026-05-28T09:00:00Z', 'AndresL230', 'canopy');
INSERT INTO doc_versions (slug, version, body, summary, status, confidence, created_at, created_by) VALUES ('adr-005-single-accent', 1, 'Context: early mocks used several accent colors and gray surfaces; state badges blurred together and the tool felt generic.

